INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, 2, -416.5, 190801, "カリン", "2025/01/31 12:00:00", 1, 1000001, "2030/01/01 14:59:59", 1, 3.414, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 0.0, 62);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2, 2, -416.5, 190801, "カリン", "2025/01/31 12:00:00", 1, 1000002, "2030/01/01 14:59:59", 1, 3.099, "ミッションをクリアして、\n報酬をゲットしましょう！", 0.0, 62);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3, 2, -416.5, 190801, "カリン", "2025/01/31 12:00:00", 1, 1000003, "2030/01/01 14:59:59", 1, 2.801, "受け取ることができる\n報酬があるようです\n確認してみてください", 0.0, 63);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (4, 2, -416.5, 190801, "カリン", "2025/01/31 12:00:00", 2, 1000004, "2030/01/01 14:59:59", 1, 0.0, "報酬がもらえますよ！\nチェックしてみてください", 0.0, 63);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (5, 1, -363.0, 190801, "カリン", "2025/01/31 12:00:00", 2, 1000005, "2030/01/01 14:59:59", 1, 2.12, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 0.0, 64);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6, 2, -363.0, 190801, "カリン", "2025/01/31 12:00:00", 1, 1000006, "2030/01/01 14:59:59", 1, 1.68, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 0.0, 64);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7, 1, -363.0, 190801, "カリン", "2025/01/31 12:00:00", 2, 1000007, "2030/01/01 14:59:59", 1, 2.33, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 0.0, 64);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (101, 7, -285.0, 133701, "ラビリスタ", "2025/01/31 12:00:00", 3, 1020101, "2030/01/01 14:59:59", 10201, 5.18, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", -6.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (201, 2, -285.0, 133901, "クリスティーナ", "2025/01/31 12:00:00", 1, 1020102, "2030/01/01 14:59:59", 10201, 8.77, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", -2.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (301, 1, -285.0, 133801, "ネネカ", "2025/01/31 12:00:00", 6, 1020103, "2030/01/01 14:59:59", 10201, 15.5, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (101, 5, -285.0, 134301, "ランファ", "2025/02/28 12:00:00", 2, 1020201, "2030/01/01 14:59:59", 10202, 9.061, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (201, 2, -285.0, 134401, "チカ", "2025/02/28 12:00:00", 1, 1020202, "2030/01/01 14:59:59", 10202, 7.699, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (101, 2, -285.0, 134601, "アオイ", "2025/03/31 12:00:00", 1, 1020301, "2030/01/01 14:59:59", 10203, 8.595, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (201, 2, -285.0, 134501, "クローチェ", "2025/03/31 12:00:00", 1, 1020302, "2030/01/01 14:59:59", 10203, 7.758, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (101, 6, -285.0, 132302, "ルイズマリー", "2025/04/30 12:00:00", 2, 1020401, "2030/01/01 14:59:59", 10204, 7.0, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (201, 2, -285.0, 132402, "イロハ", "2025/04/30 12:00:00", 1, 1020402, "2030/01/01 14:59:59", 10204, 7.904, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (301, 2, -285.0, 132502, "ソノ", "2025/04/30 12:00:00", 4, 1020403, "2030/01/01 14:59:59", 10204, 8.487, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (101, 2, -285.0, 134901, "カノン", "2025/05/31 12:00:00", 1, 1020502, "2030/01/01 14:59:59", 10205, 8.763, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (201, 3, -285.0, 134801, "ツムギ", "2025/05/31 12:00:00", 1, 1020503, "2030/01/01 14:59:59", 10205, 6.417, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (101, 7, -285.0, 135001, "エリス", "2025/06/30 12:00:00", 3, 1020601, "2030/01/01 14:59:59", 10206, 10.335, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (201, 4, -285.0, 135101, "シェフィ", "2025/06/30 12:00:00", 2, 1020602, "2030/01/01 14:59:59", 10206, 6.281, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (301, 2, -285.0, 135201, "プレシア", "2025/06/30 12:00:00", 1, 1020603, "2030/01/01 14:59:59", 10206, 12.244, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (101, 8, -285.0, 135301, "クリア", "2025/07/31 12:00:00", 2, 1020701, "2030/01/01 14:59:59", 10207, 6.339, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (201, 9, -285.0, 135401, "アネモネ", "2025/07/31 12:00:00", 7, 1020702, "2030/01/01 14:59:59", 10207, 8.184, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (101, 2, -285.0, 129101, "アイラ", "2025/08/31 12:00:00", 9, 1020801, "2030/01/01 14:59:59", 10208, 3.906, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (201, 2, -285.0, 129201, "シナツ", "2025/08/31 12:00:00", 1, 1020802, "2030/01/01 14:59:59", 10208, 14.465, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (301, 3, -285.0, 100101, "ヒヨリ", "2025/08/31 12:00:00", 4, 1020803, "2030/01/01 14:59:59", 10208, 8.662, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (401, 3, -285.0, 100301, "レイ", "2025/08/31 12:00:00", 1, 1020804, "2030/01/01 14:59:59", 10208, 10.915, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (101, 7, -285.0, 135802, "ユキノ", "2025/09/30 12:00:00", 1, 1020901, "2030/01/01 14:59:59", 10209, 6.042, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (201, 1, -285.0, 135903, "サツキ", "2025/09/30 12:00:00", 4, 1020902, "2030/01/01 14:59:59", 10209, 9.402, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (301, 1, -285.0, 136902, "ルルィ", "2025/09/30 12:00:00", 8, 1020903, "2030/01/01 14:59:59", 10209, 8.16, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (101, 2, -285.0, 137401, "カスミ", "2025/10/31 12:00:00", 3, 1021001, "2030/01/01 14:59:59", 10210, 5.0, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (201, 1, -285.0, 136001, "アラクネ", "2025/10/31 12:00:00", 4, 1021002, "2030/01/01 14:59:59", 10210, 8.12, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (301, 2, -285.0, 136202, "ナーナ", "2025/10/31 12:00:00", 4, 1021003, "2030/01/01 14:59:59", 10210, 6.386, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (101, 4, -285.0, 136402, "ユイ", "2025/11/30 12:00:00", 3, 1021101, "2030/01/01 14:59:59", 10211, 7.438, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (201, 5, -285.0, 136302, "ミソラ", "2025/11/30 12:00:00", 1, 1021102, "2030/01/01 14:59:59", 10211, 8.35, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (101, 2, -285.0, 136501, "シズル", "2025/12/31 12:00:00", 1, 1021201, "2030/01/01 14:59:59", 10212, 5.0, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (201, 2, -285.0, 137902, "リノ", "2025/12/31 12:00:00", 1, 1021202, "2030/01/01 14:59:59", 10212, 5.25, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (301, 2, -285.0, 106801, "ラビリスタ", "2025/12/31 12:00:00", 1, 1021203, "2030/01/01 14:59:59", 10212, 7.5, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (101, 2, -285.0, 126501, "ライラエル", "2026/01/31 12:00:00", 1, 1021301, "2030/01/01 14:59:59", 10213, 8.204, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (201, 2, -285.0, 129701, "ネフィ＝ネラ", "2026/01/31 12:00:00", 1, 1021302, "2030/01/01 14:59:59", 10213, 7.176, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (301, 5, -285.0, 133101, "ヴァイオレット", "2026/01/31 12:00:00", 1, 1021303, "2030/01/01 14:59:59", 10213, 8.602, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (102, 3, -285.0, 138101, "ライラエル", "2026/02/06 12:00:00", 1, 1021304, "2030/01/01 14:59:59", 10213, 10.14, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (202, 7, -285.0, 138201, "ネフィ＝ネラ", "2026/02/06 12:00:00", 1, 1021305, "2030/01/01 14:59:59", 10213, 10.152, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (302, 3, -285.0, 138001, "ヴァイオレット", "2026/02/06 12:00:00", 4, 1021306, "2030/01/01 14:59:59", 10213, 9.688, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (401, 1, -285.0, 138301, "ペコリーヌ", "2026/02/12 12:00:00", 2, 1021307, "2030/01/01 14:59:59", 10213, 5.928, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (101, 2, -285.0, 138702, "ワカナ", "2026/02/28 12:00:00", 4, 1021401, "2030/01/01 14:59:59", 10214, 9.19, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (201, 3, -285.0, 138802, "シオリ", "2026/02/28 12:00:00", 1, 1021402, "2030/01/01 14:59:59", 10214, 8.724, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (101, 1, -285.0, 138902, "グレイス", "2026/03/31 12:00:00", 4, 1021501, "2030/01/01 14:59:59", 10215, 7.758, "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (201, 4, -285.0, 139002, "キョウカ", "2026/03/31 12:00:00", 6, 1021502, "2030/01/01 14:59:59", 10215, 6.375, "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", 0.0, 61);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (301, 1, -285.0, 136902, "ルルィ", "2026/03/31 12:00:00", 6, 1021503, "2030/01/01 14:59:59", 10215, 6.173, "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", 0.0, 61);
